import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getSlotById, getAvailableSeats, bookSeats, processPayment } from '../../api/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const PAYMENT_METHODS = ['UPI','CARD','NETBANKING','WALLET'];
const PM_ICONS  = { UPI: '📱', CARD: '💳', NETBANKING: '🏦', WALLET: '👛' };
const SEAT_COLOR = { VIP: '#c97d1a', PREMIUM: '#2563a8', REGULAR: '#6b7280' };

const BookingPage = () => {
  const { slotId } = useParams();
  const navigate   = useNavigate();
  const { user }   = useAuth();

  const [slot, setSlot]             = useState(null);
  const [seatSlots, setSeatSlots]   = useState([]);
  const [selected, setSelected]     = useState([]);   // array of SeatSlot objects
  const [loading, setLoading]       = useState(true);
  const [step, setStep]             = useState(1);    // 1=seat map  2=payment  3=confirmed
  const [payMethod, setPayMethod]   = useState('UPI');
  const [booking, setBooking]       = useState(null);
  const [processing, setProcessing] = useState(false);

  useEffect(() => {
    const load = async () => {
      try {
        const [slRes, seatsRes] = await Promise.all([
          getSlotById(slotId),
          getAvailableSeats(slotId),
        ]);
        const slotData  = slRes.data?.data || null;
        const seatsData = Array.isArray(seatsRes.data?.data) ? seatsRes.data.data : [];
        setSlot(slotData);
        setSeatSlots(seatsData);
      } catch (err) {
        toast.error(err.response?.data?.message || 'Failed to load booking details');
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [slotId]);

  const toggleSeat = (ss) => {
    const alreadySelected = selected.find((s) => s.seatSlotId === ss.seatSlotId);
    if (alreadySelected) {
      setSelected((prev) => prev.filter((s) => s.seatSlotId !== ss.seatSlotId));
    } else {
      if (selected.length >= 10) { toast.error('Max 10 seats per booking'); return; }
      setSelected((prev) => [...prev, ss]);
    }
  };

  const total = selected.reduce((sum, ss) => sum + parseFloat(ss.price || 0), 0);

  const handleConfirmBooking = async () => {
    if (selected.length === 0) { toast.error('Please select at least one seat'); return; }
    setProcessing(true);
    try {
      // 1️⃣ Create reservation
      const bookRes = await bookSeats({
        userId:        user.userId,
        slotId:        parseInt(slotId),
        seatIds:       selected.map((s) => s.seat?.seatId).filter(Boolean),
        discount:      0,
        paymentMethod: payMethod,
      });
      const reservation = bookRes.data?.data;
      if (!reservation?.reservationId) throw new Error('Reservation failed — no data returned');

      // 2️⃣ Process payment
      const txnRes = await processPayment({
        reservationId:  reservation.reservationId,
        paymentMethod:  payMethod,
        amount:         total,
        discountAmount: 0,
        transactionRef: null,
      });
      const transaction = txnRes.data?.data;

      setBooking({ reservation, transaction });
      setStep(3);
      toast.success('🎉 Booking confirmed!');
    } catch (err) {
      toast.error(err.response?.data?.message || err.message || 'Booking failed. Please try again.');
    } finally {
      setProcessing(false);
    }
  };

  if (loading) return <div className="loading-center"><div className="spinner" /><span>Loading seats...</span></div>;
  if (!slot)   return (
    <div className="empty-state" style={{ marginTop: '80px' }}>
      <div className="empty-state-icon">❌</div>
      <h3>Show not found</h3>
      <button onClick={() => navigate(-1)} className="btn btn-secondary" style={{ marginTop: '16px' }}>Go Back</button>
    </div>
  );

  // Group available seats by row
  const availableSeats = seatSlots.filter((ss) => ss.availability === 'AVAILABLE');
  const rows = {};
  availableSeats.forEach((ss) => {
    const r = ss.seat?.rowLetter || '?';
    if (!rows[r]) rows[r] = [];
    rows[r].push(ss);
  });

  return (
    <div style={{ background: 'var(--bg-secondary)', minHeight: '100vh' }}>
      <div className="container" style={{ maxWidth: '960px', paddingTop: '32px', paddingBottom: '60px' }}>

        <button onClick={() => step > 1 ? setStep(step - 1) : navigate(-1)}
          className="btn btn-ghost btn-sm" style={{ marginBottom: '20px', paddingLeft: 0 }}>
          ← {step > 1 ? 'Back' : 'Back to Event'}
        </button>

        {/* ── Progress bar ── */}
        <div style={{ display: 'flex', gap: '0', marginBottom: '28px', background: 'var(--bg-card)', borderRadius: '12px', border: '1.5px solid var(--border)', overflow: 'hidden' }}>
          {[['1', 'Select Seats'], ['2', 'Payment'], ['3', 'Confirmed']].map(([num, label], i) => {
            const stepNum = i + 1;
            const isActive   = step === stepNum;
            const isComplete = step > stepNum;
            return (
              <div key={num} style={{ flex: 1, padding: '12px 16px', display: 'flex', alignItems: 'center', gap: '8px',
                background: isActive ? 'var(--accent-dim)' : isComplete ? '#f0faf6' : 'transparent',
                borderRight: i < 2 ? '1.5px solid var(--border)' : 'none',
              }}>
                <div style={{ width: 24, height: 24, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '12px', fontWeight: 700,
                  background: isActive ? 'var(--accent)' : isComplete ? 'var(--green)' : 'var(--border)',
                  color: isActive || isComplete ? 'white' : 'var(--text-muted)',
                }}>
                  {isComplete ? '✓' : num}
                </div>
                <span style={{ fontSize: '13px', fontWeight: isActive ? 700 : 500, color: isActive ? 'var(--accent)' : isComplete ? 'var(--green)' : 'var(--text-muted)' }}>
                  {label}
                </span>
              </div>
            );
          })}
        </div>

        {/* ── Slot info ── */}
        <div className="card" style={{ padding: '18px 24px', marginBottom: '24px' }}>
          <div style={{ display: 'flex', gap: '24px', flexWrap: 'wrap', alignItems: 'center' }}>
            <div style={{ flex: 1 }}>
              <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.3rem', fontWeight: 400, color: 'var(--text-primary)' }}>
                {slot.event?.name || 'Show'}
              </div>
              <div style={{ fontSize: '13px', color: 'var(--text-secondary)', marginTop: '5px', fontWeight: 500, display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                <span>📅 {slot.showDate}</span>
                <span>⏰ {slot.startTime?.slice(0,5)} – {slot.endTime?.slice(0,5)}</span>
                {slot.location?.locName && <span>📍 {slot.location.locName}</span>}
              </div>
            </div>
            <div style={{ textAlign: 'right' }}>
              <div style={{ fontSize: '11px', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.5px', fontWeight: 600 }}>Seats Available</div>
              <div style={{ fontFamily: 'var(--font-display)', fontSize: '2rem', fontWeight: 400, color: slot.seatsLeft > 20 ? 'var(--green)' : 'var(--gold)' }}>
                {slot.seatsLeft}
              </div>
            </div>
          </div>
        </div>

        {/* ── Step 3: Confirmation ── */}
        {step === 3 && booking && (
          <div style={{ maxWidth: '480px', margin: '0 auto', textAlign: 'center' }}>
            <div className="card" style={{ padding: '48px 40px', border: '2px solid var(--green)', boxShadow: '0 8px 32px rgba(26,143,99,0.12)' }}>
              <div style={{ fontSize: '64px', marginBottom: '16px' }}>🎉</div>
              <h2 style={{ fontFamily: 'var(--font-display)', fontSize: '2.2rem', fontWeight: 400, color: 'var(--green)', marginBottom: '6px' }}>
                Booking Confirmed!
              </h2>
              <p style={{ color: 'var(--text-muted)', marginBottom: '28px', fontSize: '14px' }}>
                Your tickets are booked successfully
              </p>
              <div style={{ background: 'var(--bg-secondary)', borderRadius: '10px', padding: '18px', marginBottom: '24px', textAlign: 'left' }}>
                <InfoRow label="Ref Code"       value={booking.reservation?.refCode} mono />
                <InfoRow label="Amount Paid"    value={`₹${parseFloat(booking.reservation?.amount || 0).toFixed(2)}`} />
                <InfoRow label="Payment"        value={booking.transaction?.paymentMethod} />
                <InfoRow label="Txn Ref"        value={booking.transaction?.transactionRef || 'N/A'} mono />
                <InfoRow label="Status"         value="✅ Confirmed" last />
              </div>
              <div style={{ display: 'flex', gap: '12px' }}>
                <button onClick={() => navigate('/my-bookings')} className="btn btn-primary" style={{ flex: 1 }}>
                  My Bookings
                </button>
                <button onClick={() => navigate('/')} className="btn btn-secondary" style={{ flex: 1 }}>
                  Browse More
                </button>
              </div>
            </div>
          </div>
        )}

        {/* ── Step 2: Payment ── */}
        {step === 2 && (
          <div style={{ maxWidth: '480px', margin: '0 auto' }}>
            <div className="card" style={{ padding: '28px', marginBottom: '16px' }}>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.4rem', fontWeight: 400, marginBottom: '20px' }}>Order Summary</h3>
              {selected.map((s) => (
                <div key={s.seatSlotId} style={{ display: 'flex', justifyContent: 'space-between', padding: '9px 0', borderBottom: '1px solid var(--border)', fontSize: '14px' }}>
                  <span style={{ color: 'var(--text-secondary)', fontWeight: 500 }}>
                    Seat {s.seat?.rowLetter}{s.seat?.seatNo}
                    <span style={{ fontSize: '11px', marginLeft: '6px', color: 'var(--text-muted)' }}>({s.seat?.seatType})</span>
                  </span>
                  <span style={{ fontWeight: 700 }}>₹{parseFloat(s.price).toFixed(2)}</span>
                </div>
              ))}
              <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '14px', paddingTop: '4px' }}>
                <span style={{ fontWeight: 700, fontSize: '15px' }}>Total</span>
                <span style={{ fontFamily: 'var(--font-display)', fontSize: '1.5rem', fontWeight: 400, color: 'var(--accent)' }}>
                  ₹{total.toFixed(2)}
                </span>
              </div>
            </div>

            <div className="card" style={{ padding: '28px' }}>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.4rem', fontWeight: 400, marginBottom: '20px' }}>Payment Method</h3>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px', marginBottom: '24px' }}>
                {PAYMENT_METHODS.map((m) => (
                  <button key={m} onClick={() => setPayMethod(m)}
                    style={{ padding: '14px', borderRadius: '10px', border: '1.5px solid', cursor: 'pointer', fontWeight: 700, fontSize: '14px', transition: 'var(--transition)', fontFamily: 'var(--font-body)',
                      borderColor: payMethod === m ? 'var(--accent)' : 'var(--border)',
                      background:  payMethod === m ? 'var(--accent-dim)' : 'var(--bg-card)',
                      color:       payMethod === m ? 'var(--accent)' : 'var(--text-secondary)',
                    }}>
                    <div style={{ fontSize: '22px', marginBottom: '4px' }}>{PM_ICONS[m]}</div>
                    {m}
                  </button>
                ))}
              </div>
              <button onClick={handleConfirmBooking} disabled={processing} className="btn btn-primary btn-full btn-lg">
                {processing ? '⏳ Processing...' : `Pay ₹${total.toFixed(2)}`}
              </button>
            </div>
          </div>
        )}

        {/* ── Step 1: Seat Map ── */}
        {step === 1 && (
          <>
            {/* Legend */}
            <div style={{ display: 'flex', gap: '20px', marginBottom: '16px', flexWrap: 'wrap', alignItems: 'center' }}>
              <div style={{ display: 'flex', gap: '16px' }}>
                {[['Available', 'white', 'var(--border)'], ['Selected', 'var(--accent)', 'var(--accent)'], ['Booked', '#f0f0f0', '#ddd']].map(([label, bg, border]) => (
                  <div key={label} style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '12px', color: 'var(--text-secondary)', fontWeight: 500 }}>
                    <div style={{ width: 18, height: 16, background: bg, border: `2px solid ${border}`, borderRadius: '3px 3px 1px 1px' }} />
                    {label}
                  </div>
                ))}
              </div>
              <div style={{ marginLeft: 'auto', display: 'flex', gap: '14px' }}>
                {Object.entries(SEAT_COLOR).map(([type, color]) => (
                  <span key={type} style={{ fontSize: '12px', color, fontWeight: 600, display: 'flex', alignItems: 'center', gap: '4px' }}>
                    <span style={{ width: 8, height: 8, background: color, borderRadius: '50%', display: 'inline-block' }} />
                    {type}
                  </span>
                ))}
              </div>
            </div>

            {/* Screen */}
            <div style={{ textAlign: 'center', marginBottom: '20px', padding: '8px 24px', background: 'linear-gradient(to bottom, #e5e1d8, #f0ece4)', borderRadius: '6px', border: '1.5px solid var(--border)', fontSize: '11px', color: 'var(--text-muted)', letterSpacing: '6px', textTransform: 'uppercase', fontWeight: 600 }}>
              SCREEN
            </div>

            {/* Seat grid */}
            <div className="card" style={{ padding: '24px', overflowX: 'auto', marginBottom: '16px' }}>
              {availableSeats.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '40px', color: 'var(--text-muted)' }}>
                  <div style={{ fontSize: '40px', marginBottom: '12px' }}>😔</div>
                  <div style={{ fontWeight: 600 }}>No seats available for this show</div>
                  <div style={{ fontSize: '13px', marginTop: '6px' }}>All seats have been booked</div>
                </div>
              ) : (
                Object.entries(rows).sort().map(([row, seats]) => (
                  <div key={row} style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                    <span style={{ width: '22px', fontSize: '12px', color: 'var(--text-muted)', fontFamily: 'var(--font-mono)', textAlign: 'center', flexShrink: 0, fontWeight: 700 }}>
                      {row}
                    </span>
                    <div style={{ display: 'flex', gap: '5px', flexWrap: 'wrap' }}>
                      {[...seats].sort((a, b) => (a.seat?.seatNo || 0) - (b.seat?.seatNo || 0)).map((ss) => {
                        const isSelected  = !!selected.find((s) => s.seatSlotId === ss.seatSlotId);
                        const c = SEAT_COLOR[ss.seat?.seatType] || '#6b7280';
                        return (
                          <button key={ss.seatSlotId} onClick={() => toggleSeat(ss)}
                            title={`${ss.seat?.rowLetter || row}${ss.seat?.seatNo} · ${ss.seat?.seatType} · ₹${ss.price}`}
                            style={{ width: '38px', height: '34px', borderRadius: '6px 6px 2px 2px', cursor: 'pointer', transition: 'var(--transition)', fontFamily: 'var(--font-mono)', fontSize: '10px', fontWeight: 700,
                              border:      isSelected ? '2px solid var(--accent)' : `2px solid ${c}55`,
                              background:  isSelected ? 'var(--accent)'           : `${c}18`,
                              color:       isSelected ? 'white'                   : c,
                              transform:   isSelected ? 'scale(1.1)'              : 'scale(1)',
                            }}>
                            {ss.seat?.seatNo}
                          </button>
                        );
                      })}
                    </div>
                  </div>
                ))
              )}
            </div>

            {/* Sticky bottom bar */}
            {selected.length > 0 && (
              <div style={{ position: 'sticky', bottom: '16px', background: 'white', borderRadius: '14px', border: '2px solid var(--accent)', padding: '16px 24px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '16px', flexWrap: 'wrap', boxShadow: '0 8px 32px rgba(224,92,42,0.2)' }}>
                <div>
                  <div style={{ fontSize: '13px', color: 'var(--text-secondary)', marginBottom: '4px', fontWeight: 500 }}>
                    {selected.length} seat{selected.length > 1 ? 's' : ''} selected:{' '}
                    <strong>{selected.map((s) => `${s.seat?.rowLetter || ''}${s.seat?.seatNo || ''}`).join(', ')}</strong>
                  </div>
                  <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.6rem', fontWeight: 400, color: 'var(--accent)' }}>
                    ₹{total.toFixed(2)}
                  </div>
                </div>
                <button onClick={() => setStep(2)} className="btn btn-primary btn-lg">
                  Proceed to Payment →
                </button>
              </div>
            )}
          </>
        )}

      </div>
    </div>
  );
};

const InfoRow = ({ label, value, mono, last }) => (
  <div style={{ display: 'flex', justifyContent: 'space-between', padding: '8px 0', borderBottom: last ? 'none' : '1px solid var(--border)', fontSize: '13px' }}>
    <span style={{ color: 'var(--text-muted)', fontWeight: 600 }}>{label}</span>
    <span style={{ fontFamily: mono ? 'var(--font-mono)' : 'var(--font-body)', fontWeight: 700, color: 'var(--text-primary)' }}>{value}</span>
  </div>
);

export default BookingPage;
